"use strict";parserFactory.register("ficbook.net",()=>new FicbookParser),parserFactory.register("fic.fan",()=>new FicbookParser),parserFactory.register("fanfictionero.com",()=>new FicbookParser),parserFactory.register("ficador.com",()=>new FicbookParser);class FicbookParser extends Parser{constructor(){super()}async getChapterUrls(e,t){let r=[...e.querySelectorAll("a.part-link")];if(0==r.length)return[{sourceUrl:e.baseURI,title:e.querySelector("#part_content > div.title-area.text-center.word-break > h2").textContent}];let n=[];for(let e of r)n.push({sourceUrl:e.href,title:e.innerText}),t.showTocProgress(n);return n}findCoverImageUrl(e){return e.querySelector("meta[property='og:image']").getAttribute("content")}findContent(e){return e.querySelector("#content")}customRawDomToContentStep(e,t){let r=t.innerText.split("\n\n").map(e=>"<p>"+e+"</p>").join(""),n=util.sanitize("<div id='content'>"+r+"</div>").querySelector("#content");t.replaceChildren(),util.moveChildElements(n,t)}extractTitleImpl(e){return e.querySelector("h1.heading")}extractAuthor(e){let t=e.querySelector("a.creator-username")?.innerText;return t??super.extractAuthor(e)}extractLanguage(e){return e.querySelector("html").getAttribute("lang")}extractSubject(e){return[...e.querySelectorAll("div.description strong, div.description a")].map(e=>e.textContent).join(", ")}extractDescription(e){return e.querySelector("meta[name='description']")?.textContent}extractSeriesInfo(e,t){t.fileName=this.extractTitleImpl(e).textContent}findChapterTitle(e){return e.querySelector("#part_content h2[itemprop='headline']")}}